function shortenURL(e, t) {
    const n = `https://tinyurl.com/api-create.php?url=${encodeURIComponent(e)}`;
    fetch(n)
        .then((e) => {
            if (e.ok) {
                return e.text();
            } else {
                throw new Error("Error al acortar la URL");
            }
        })
        .then((e) => {
            t(e);
        })
        .catch((e) => {
            console.error("Error al acortar la URL:", e);
            t(null);
        });
}
